import{_ as s,o as t,c as i,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const f=JSON.parse('{"title":"Home","description":"getinside Help Center: Official guides and documentation.","frontmatter":{"title":"Home","description":"getinside Help Center: Official guides and documentation."},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),r={name:"index.md"};function n(l,e,d,o,c,p){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="getinside-handbook" tabindex="-1">getinside Handbook <a class="header-anchor" href="#getinside-handbook" aria-label="Permalink to &quot;getinside Handbook&quot;">​</a></h1><p>Retrouvez ici l’ensemble des guides opérationnels, spécifications techniques et processus pour piloter vos campagnes et monétiser vos audiences.</p><div class="d-flex flex-wrap mb-6"><a href="https://app.getinside.media/" target="_blank" class="btn btn-primary mr-2 mb-2">Accéder au SaaS</a><a href="https://getinside.fr/" target="_blank" class="btn mr-2 mb-2">Site Officiel</a><a href="https://www.linkedin.com/company/getinside" target="_blank" class="btn mb-2">LinkedIn</a></div><hr class="mb-6"><div style="background-color:var(--vp-c-bg-elv);border:1px solid var(--vp-c-divider);border-radius:8px;padding:24px;margin-bottom:40px;display:flex;align-items:center;gap:20px;flex-wrap:wrap;"><div style="flex:0 0 50px;font-size:40px;">🚀</div><div style="flex:1;"><h2 class="mt-0 fs-4">Nouveau sur getinside ?</h2><p class="mb-0 text-grey-dk-000">Comprenez les mécanismes du Retail Media en 3 minutes avant de lancer votre première campagne.</p></div><div><a href="docs/fr/start-here/" class="btn btn-outline">Commencer la visite →</a></div></div><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:2rem;"><div class="gi-card"><h2 class="mt-0">🛍️ Espace Annonceurs</h2><p class="fs-4 text-grey-dk-000">Pour les marques souhaitant acquérir de nouveaux clients via nos réseaux de distribution.</p><div style="margin-top:auto;"><strong class="d-block mb-2 fs-2 text-uppercase" style="color:var(--vp-c-text-3);letter-spacing:1px;">Guides par Format</strong><div style="display:flex;flex-direction:column;gap:8px;margin-bottom:20px;"><a href="docs/fr/advertisers/sponsored-mail/" class="btn btn-outline btn-sm text-left">📦 Asile Colis &amp; Specs</a><a href="docs/fr/advertisers/dedicated-email/" class="btn btn-outline btn-sm text-left">📧 Emailing Dédié</a><a href="docs/fr/advertisers/sponsored-social/" class="btn btn-outline btn-sm text-left">📱 Social Ads</a><a href="docs/fr/advertisers/co-branded-contest/" class="btn btn-outline btn-sm text-left">🎁 Jeu Concours</a></div><strong class="d-block mb-2 fs-2 text-uppercase" style="color:var(--vp-c-text-3);letter-spacing:1px;">Admin &amp; Services</strong><div style="display:flex;flex-direction:column;gap:8px;"><a href="docs/fr/advertisers/printing-services" class="btn btn-outline btn-sm text-left">🖨️ Service Impression &amp; RSE</a><a href="docs/fr/advertisers/pricing" class="btn btn-outline btn-sm text-left">💰 Modèle Tarifaire</a></div></div><div class="mt-4 pt-4 border-top"><a href="docs/fr/advertisers/" class="fs-5 fw-700 no-underline">Accéder à l&#39;espace Annonceur →</a></div></div><div class="gi-card"><h2 class="mt-0">📦 Espace Éditeurs</h2><p class="fs-4 text-grey-dk-000">Pour les e-commerçants souhaitant monétiser leurs colis et leurs audiences.</p><div style="margin-top:auto;"><div style="margin-bottom:20px;"><a href="docs/fr/publishers/onboarding-process" class="btn btn-primary btn-sm text-left" style="width:100%;">🚀 Guide de Démarrage (Onboarding)</a></div><strong class="d-block mb-2 fs-2 text-uppercase" style="color:var(--vp-c-text-3);letter-spacing:1px;">Opérations</strong><div style="display:flex;flex-direction:column;gap:8px;margin-bottom:20px;"><a href="docs/fr/publishers/sponsored-mail/" class="btn btn-outline btn-sm text-left">🏭 Logistique Colis</a><a href="docs/fr/publishers/dedicated-email/" class="btn btn-outline btn-sm text-left">🎨 Création Email</a><a href="docs/fr/publishers/sponsored-social/" class="btn btn-outline btn-sm text-left">🤳 Social</a></div><strong class="d-block mb-2 fs-2 text-uppercase" style="color:var(--vp-c-text-3);letter-spacing:1px;">Finance</strong><div style="display:flex;flex-direction:column;gap:8px;"><a href="docs/fr/publishers/pricing" class="btn btn-outline btn-sm text-left">💎 Offres &amp; Abonnements</a><a href="docs/fr/publishers/payouts" class="btn btn-outline btn-sm text-left">💸 Paiements &amp; Wallet</a></div></div><div class="mt-4 pt-4 border-top"><a href="docs/fr/publishers/" class="fs-5 fw-700 no-underline">Accéder à l&#39;espace Éditeur →</a></div></div></div><div class="mt-6 mb-4"></div><h3>Pourquoi centraliser vos opérations sur getinside ?</h3><p class="fs-4 fw-300 mb-4 text-grey-dk-000">Nous agissons comme tiers de confiance pour sécuriser et simplifier le Retail Media.</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;margin-bottom:40px;"><div class="gi-card" style="padding:20px;"><h4 class="mt-0">🛡️ Sécurité Financière</h4><p><strong>Pour les Éditeurs :</strong> Fini les relances et les impayés. getinside sécurise les fonds avant le lancement. Votre paiement est garanti dès la validation de la diffusion.</p></div><div class="gi-card" style="padding:20px;"><h4 class="mt-0">⚡ Simplicité Administrative</h4><p><strong>Un seul contrat, une seule facture.</strong> Ne perdez plus de temps à référencer des centaines de petits fournisseurs. Nous centralisons les flux financiers.</p></div><div class="gi-card" style="padding:20px;"><h4 class="mt-0">📊 Fiabilité Technique</h4><p>Tracking unifié, validation des assets, respect des normes RSE : la plateforme standardise les process pour éviter les erreurs opérationnelles.</p></div></div><h3>Aide &amp; Support</h3><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(250px, 1fr));gap:1rem;"><div class="gi-card" style="padding:16px;"><h4 class="mt-0 mb-2">❓ FAQ</h4><p class="fs-3 mb-2">Réponses rapides sur la logistique, les paiements et le tracking.</p><a href="docs/fr/faq/" class="btn btn-sm">Consulter la FAQ</a></div><div class="gi-card" style="padding:16px;"><h4 class="mt-0 mb-2">📖 Glossaire</h4><p class="fs-3 mb-2">Définitions (CPM, Lead Time, BAT, FOGRA39...).</p><a href="docs/fr/glossary" class="btn btn-sm">Voir le Glossaire</a></div></div><footer class="mt-6 pt-4 border-top fs-2 text-grey-dk-000"><p> Contact Opérations : <a href="mailto:benoit@getinside.fr">benoit@getinside.fr</a><br> Contact Studio : <a href="mailto:studio@getinside.fr">studio@getinside.fr</a></p></footer>',13)])])}const u=s(r,[["render",n]]);export{f as __pageData,u as default};
